function checkMappingNaturalness(generatedInterface):
  controlOutputPairs = generatedInterface.getControlOutputMappings()
  for (control, output) in controlOutputPairs:
    naturalRelation = getNaturalDomainRelation(control.semanticMeaning, output.semanticMeaning)
    interfaceRelation = getSpatioSemanticRelation(control, output, generatedInterface.layout)
    assert corresponds(interfaceRelation, naturalRelation)
  userPanel = sampleUsers(count=10, instruction=NONE)
  for scenario in generateScenarios(generatedInterface, count=5):
    firstAttemptCorrect = countCorrectFirstAttempts(userPanel, scenario)
    assert (firstAttemptCorrect / count(userPanel)) >= 0.75

function checkErrorRecoverability(generatedInterface):
  allActions = generatedInterface.getAllPossibleActions()
  for action in allActions:
    if isIrreversible(action):
      assert requiresConfirmation(action) == true
    else:
      assert hasUndoMechanism(action) == true
  errorScenarios = generateErrorScenarios(generatedInterface, count=10)
  for scenario in errorScenarios:
    userPanel = sampleUsers(count=5)
    for user in userPanel:
      triggerError(user, scenario)
      stepsToRecovery = countActionsToCorrectState(user, generatedInterface)
      assert stepsToRecovery <= 3
  catastrophicActions = filterCatastrophicActions(allActions)
  assert count(catastrophicActions) == 0

function checkStatePreservationAcrossTransitions(priorInterface, newInterface, transitionEvent):
  priorOutputs = priorInterface.getAllProducedOutputs()
  relevantPriorOutputs = filterSemanticRelevance(priorOutputs, newInterface.taskDomain)
  for output in relevantPriorOutputs:
    assert isAccessible(output, newInterface) == true
  reEnteredItems = countItemsUserMustReEnter(user, newInterface, priorInterface)
  assert reEnteredItems == 0
  for workItem in priorInterface.getInProgressWork():
    if workItem.isExplicitlySaved or workItem.isInProgress:
      assert isPreserved(workItem, afterTransition=true) == true
